window.QB_EN_AIRPORT.push(
  {c:'出国',q:'你到达机场，想知道登机口在哪里，应该问？',o:['Where is gate B12?','Where is the baggage claim?','What time does the plane land?','Can I upgrade my ticket?'],a:0,e:'gate=登机口，直接说"Where is gate ___?"就能问到位置。机场内有大量指示牌，留意Departures（出发）方向。'},
  {c:'出国',q:'机场工作人员说"Your flight has been delayed by two hours."，意思是？',o:['你的航班延误了两小时','你的航班已被取消','你的航班提前了两小时','你需要重新办理值机'],a:0,e:'delayed=延误，delayed by two hours=延误两小时。遇到延误可以问："Is there a voucher for meals?"（有餐食补偿券吗？）'},
  {c:'出国',q:'"Overweight baggage fee"是指什么费用？',o:['行李超重费','行李遗失赔偿','托运手续费','行李保险费'],a:0,e:'overweight=超重，baggage=行李。大多数航空公司托运行李有重量限制（经济舱通常20-23kg），超重要额外付费。'},
  {c:'出国',q:'你想知道航班是否准时出发，可以查什么？',o:['Departure board / Flight status board（出发信息大屏）','Arrival board','Baggage carousel','Security checkpoint'],a:0,e:'Departure board=出发航班信息屏，显示航班号、目的地、状态（On Time准时 / Delayed延误 / Cancelled取消 / Boarding登机）。'},
  {c:'出国',q:'"Please proceed to the security checkpoint."这句话要求你做什么？',o:['前往安检通道','前往登机口','去取行李','去购买机票'],a:0,e:'proceed=前进/前往，security checkpoint=安检口。机场广播或工作人员说这句话时，请往安检方向走。'},
  {c:'出国',q:'机票上"Economy Class"是指？',o:['经济舱','商务舱','头等舱','豪华经济舱'],a:0,e:'Economy Class=经济舱（最便宜），Business Class=商务舱，First Class=头等舱，Premium Economy=超级经济舱/豪华经济舱。'},
  {c:'出国',q:'"I\'d like to request a wheelchair assistance."这句话用于什么情况？',o:['为行动不便的旅客申请轮椅服务','要求升舱','申请婴儿摇篮','预订特殊餐食'],a:0,e:'wheelchair assistance=轮椅服务。老人或行动不便者可在办理值机时提出，机场会安排专人推轮椅全程陪同。'},
  {c:'出国',q:'在机场,"Lost and Found"是什么地方？',o:['失物招领处','行李认领处','旅客信息中心','出入境管理处'],a:0,e:'Lost and Found=失物招领处。在机场内遗失物品（如手机、钱包）可前往此处询问。也叫Lost Property Office（英式）。'},
  {c:'出国',q:'你想选靠近前舱的座位，应该要求？',o:['Bulkhead seat or a seat near the front','A seat at the back','A middle seat','A seat near the emergency exit'],a:0,e:'Bulkhead seat=隔断座（腿部空间大），near the front=靠近前舱。选择靠前座位下飞机快，适合转机时间紧张的旅客。'},
  {c:'出国',q:'"Hand luggage / carry-on baggage"的重量限制通常是？',o:['大多数航空公司限制7-10kg','大多数航空公司限制23kg','没有重量限制','只限制尺寸不限制重量'],a:0,e:'手提行李（carry-on/hand luggage）通常限重7kg（廉价航空）到10kg，需放入头顶行李舱（overhead bin）。'},
  {c:'出国',q:'"Transit visa"（过境签证）是什么情况下需要的？',o:['某些国家规定，在该国机场转机且需出机场时，必须持有过境签证','所有转机旅客都需要','只有停留超过24小时才需要','持有申根签证则无需过境签'],a:0,e:'过境签（Transit Visa）的要求因国而异。如转机美国（即使不出机场），中国公民通常仍需签证。出发前必须提前核查！'},
  {c:'出国',q:'机场广播说"Flight MU586 is now boarding at gate C8."，意思是？',o:['MU586航班现在在C8登机口开始登机','MU586航班已延误','C8登机口关闭','请前往C8换乘'],a:0,e:'now boarding=正在登机，gate=登机口。听到本次航班的登机广播，要尽快前往对应登机口。'},
  {c:'出国',q:'办理值机时，"Seat assignment"是指什么？',o:['座位分配/座位号','行李托运单','值机手续费','座舱等级'],a:0,e:'seat assignment=座位分配，指你在飞机上的具体座位（如23A）。可以在网上提前选座，或在柜台办理时请工作人员安排。'},
  {c:'出国',q:'"Airside"和"Landside"在机场中各指什么？',o:['Airside=安检后的区域（免税店在此），Landside=安检前的公共区域','Airside=国际区，Landside=国内区','两者含义相同','Airside=跑道区，Landside=停机坪'],a:0,e:'Landside=安检前（公共区），Airside=安检后（只有旅客和机组人员能进入）。免税店、餐厅、登机口都在Airside。'},
  {c:'出国',q:'你的航班被取消了，应该首先怎么做？',o:['联系航空公司或前往其服务柜台，要求安排改签或退款','立即买另一家航空公司的票','投诉机场','自行离开等待通知'],a:0,e:'航班取消（cancelled）时，前往航空公司柜台说："My flight was cancelled. I\'d like to rebook or get a refund."（我的航班被取消了，我想改签或退款）。'},
  {c:'出国',q:'"E-ticket"（电子机票）和传统纸质机票有何区别？',o:['电子机票以电子形式存储，用订单号或二维码办理值机，更方便环保','电子机票不能托运行李','纸质机票登机更快','电子机票只适用于国内航班'],a:0,e:'现在几乎全部使用E-ticket（电子机票）。只需记住订单号（booking reference/PNR）或打印二维码，即可在机场自助办理值机。'}
);

