window.QB_EN_HOTEL.push(
  {c:'出国',q:'你想要一间禁烟房，应该怎么说？',o:['I\'d like a non-smoking room, please.','I need a room with a balcony.','Can I have a king-size bed?','I want a suite.'],a:0,e:'non-smoking room=禁烟房。如果你对烟味敏感，入住时务必要求non-smoking room，否则可能分到有烟味的房间。'},
  {c:'出国',q:'"Room service"是指？',o:['客房送餐/上门服务（可以打电话要食物或饮品送到房间）','房间清洁服务','接待服务','叫早电话服务'],a:0,e:'Room service=客房送餐服务。拨打酒店内线，工作人员会把餐食送到你房间。通常比餐厅贵，但非常方便！'},
  {c:'出国',q:'你发现房间里有蟑螂，应该如何向前台反映？',o:['There\'s a cockroach in my room. I\'d like to change rooms.','My room is noisy.','The light is broken.','I need more pillows.'],a:0,e:'cockroach=蟑螂，change rooms=换房间。遇到任何卫生或安全问题，立即联系前台要求换房或处理，这是你的合理权利。'},
  {c:'出国',q:'"Concierge"是酒店的什么服务？',o:['礼宾部，提供旅游建议、预订餐厅、叫车等个性化服务','前台接待','客房清洁','行李寄存'],a:0,e:'concierge（发音：con-SEERJ）=礼宾员，是高档酒店的特色服务，可以帮你预订门票、推荐餐厅、安排行程，是旅行中很好用的资源。'},
  {c:'出国',q:'你到达酒店时发现房间还没打扫好，前台说"Your room is not ready yet."，你可以？',o:['Leave your luggage with the bellhop and explore the area first.（把行李交给行李员先去转转）','要求立即退款','直接自己去打扫','换一家酒店'],a:0,e:'bellhop/bellboy=行李员。如果房间还没准备好，可以寄存行李（luggage storage）先出去玩，等前台通知你房间已准备好。'},
  {c:'出国',q:'"The hotel offers complimentary breakfast."的意思是？',o:['酒店提供免费早餐','酒店早餐价格合理','酒店有多种早餐选择','早餐只限于住客'],a:0,e:'complimentary=免费赠送（来自酒店的礼貌）。"Complimentary breakfast"=免费早餐。此外，欢迎水果、minibar饮料也常被称为complimentary。'},
  {c:'出国',q:'你要离开城市继续旅程，但退房时间前不想闲着，可以要求？',o:['Luggage storage / Can I store my bags here until my flight?','Late check-in','Early check-out discount','Room upgrade'],a:0,e:'Luggage storage/Baggage storage=行李寄存。大多数酒店提供免费或低价的行李寄存服务，退房后继续游玩非常方便。'},
  {c:'出国',q:'"Late check-out"是指什么？通常需要额外付费吗？',o:['延迟退房（比标准退房时间晚）；通常需要额外付费或视房间情况而定','提前入住，通常免费','取消预订，可能收费','升级房型，通常免费'],a:0,e:'late check-out=延迟退房。如需延迟，提前联系前台说"Can I have a late check-out?"部分酒店会视入住率免费提供，有时收半天房费。'},
  {c:'出国',q:'你的房间钥匙卡失效了，应该说？',o:['My key card doesn\'t work. Could you reprogram it?','My room is locked.','I forgot my room number.','I lost my key.'],a:0,e:'key card=门卡，doesn\'t work / stopped working=失效了，reprogram=重新激活。只需带上房卡去前台，工作人员会马上帮你重新激活。'},
  {c:'出国',q:'"Minibar"在酒店客房中是指什么？',o:['房间内的小冰箱，内含饮料和零食（通常需额外付费）','小型浴室','床头灯控制器','迷你书柜'],a:0,e:'Minibar=客房小冰箱，内装饮料、零食、酒类。方便但价格昂贵（通常是超市的3-5倍），结账时会按使用计费。'},
  {c:'出国',q:'你想预订带浴缸的房间，应该说？',o:['I\'d like a room with a bathtub, please.','I need a room with a shower only.','Do you have a Jacuzzi suite?','Can I have a pool-view room?'],a:0,e:'bathtub=浴缸，shower=淋浴。想泡澡一定要提前确认，因为很多现代酒店客房只有淋浴设施，没有浴缸。'},
  {c:'出国',q:'"Turn down service"是酒店提供的什么服务？',o:['夜床服务（傍晚整理床铺、拉窗帘，有时放置巧克力）','叫早服务','夜间送餐','24小时前台服务'],a:0,e:'Turn-down service=开床服务，是高档酒店提供的服务，通常在晚间整理床铺、翻开被角、放置枕头薄荷糖，营造温馨的就寝氛围。'},
  {c:'出国',q:'你订的是"Twin room"，这是指？',o:['有两张单人床的双人间','有一张大床的双人间','三人间','家庭套房'],a:0,e:'Twin room=两张单人床（single beds）的双人间，适合两个朋友或不想睡同一张床的情侣。Double room=一张大床。'},
  {c:'出国',q:'酒店大堂的"Valet parking"是什么服务？',o:['代客泊车服务（你把钥匙交给酒店工作人员，他们帮你停车）','免费停车','自助停车','租车服务'],a:0,e:'Valet parking=代客泊车，是高档酒店常见服务。在大门口把车钥匙交给服务员，他们帮你停车，取车时再叫来。通常需要付小费。'},
  {c:'出国',q:'酒店账单上出现"Incidentals hold"，这是什么？',o:['预授权押金（用于防止宾客使用minibar/破坏物品，退房结算后会退还）','额外服务费','旅游税','网络费'],a:0,e:'Incidentals hold=预授权冻结，是酒店在信用卡上预先冻结一定金额（如$100-200），退房后如无损耗会全额返还。刷卡入住时要有余额！'}
);

// ──────────────────────────────────────────────────────────────
// 【3】交通出行英语 新增 ×15
// ──────────────────────────────────────────────────────────────
window.QB_EN_TRANSPORT.push(
  {c:'出国',q:'你想坐出租车到市中心，上车后应该怎么说？',o:['To the city center / downtown, please.','I\'d like to go to the airport.','How far is it?','Is the meter running?'],a:0,e:'直接说目的地+please是最简单的方式。"To [地名], please."上车就用。也可以把地址写在手机上展示给司机，避免沟通障碍。'},
  {c:'出国',q:'"Is the meter running?"在打车时是什么意思？',o:['计价器开始计费了吗（确认司机有没有开始计价）','车速有多快','我们什么时候到','有没有收费公路'],a:0,e:'meter=计价器，running=运行中。上出租车后确认计价器是否开启，避免被漫天要价。如没开，说"Please turn on the meter."'},
  {c:'出国',q:'在英国，"Tube map"是什么？',o:['伦敦地铁线路图','伦敦公交路线图','伦敦旅游地图','英国火车时刻表'],a:0,e:'Tube=伦敦地铁（Underground的俗称），Tube map=伦敦地铁线路图。颜色区分线路，是游览伦敦必备工具，各大地铁站免费领取。'},
  {c:'出国',q:'"Peak hours"（高峰时段）在城市交通中通常是指？',o:['早7-9点和晚5-7点（上下班高峰）','中午12-1点','凌晨0-3点','全天任意时间'],a:0,e:'Peak hours=交通高峰期，通常是工作日的早晨和傍晚。高峰期交通拥堵，地铁可能人满为患，票价也可能更贵（如伦敦地铁）。'},
  {c:'出国',q:'"Hop-on hop-off bus"是什么类型的旅游产品？',o:['随上随下观光巴士（可在景点随意上下，票通常全天有效）','机场大巴','城市之间的长途巴士','包车服务'],a:0,e:'Hop-on hop-off（HOHO）bus是旅游城市常见的观光巴士，购买全日票可自由在各景点上下车，很多有录音导览，性价比高。'},
  {c:'出国',q:'在美国，"Freeway"和"Highway"有什么区别？',o:['Freeway=无收费的高速公路，Highway=公路（可能有收费站）','两者完全相同','Freeway更安全','Highway速度更快'],a:0,e:'Freeway=免费高速（free+way），Highway=公路（更广泛的含义，包括收费/免费）。Toll road=收费公路，Turnpike=收费高速（东部常见）。'},
  {c:'出国',q:'你在路口看到"Yield"标志，应该怎么做？',o:['减速，让已在路口或主干道行驶的车辆先行','停车等候红灯','禁止转弯','禁止超车'],a:0,e:'Yield=让行（美式），相当于英式的"Give Way"。三角形标志，在汇入主干道或遇到来车时减速礼让，不是完全停车（那是Stop）。'},
  {c:'出国',q:'"Round trip"和"One-way"票有什么区别？',o:['Round trip=来回票（往返），One-way=单程票（只去不回）','One-way更贵','Round trip只用于飞机','两者价格相同'],a:0,e:'One-way ticket=单程票，Round trip（美式）/ Return ticket（英式）=往返票。提前购买往返票通常比两张单程便宜。'},
  {c:'出国',q:'你在日本想购买一张可以无限次乘坐的交通IC卡，应该买？',o:['Suica / Pasmo（可充值的交通IC卡）','Shinkansen pass','Japan Rail Pass','Day pass'],a:0,e:'Suica（西瓜卡）和Pasmo是日本两种主要的充值式交通IC卡，可用于地铁、公交、部分便利店消费，旅游十分实用。'},
  {c:'出国',q:'"Rideshare"（拼车/网约车）在国外出行常见的App有哪些？',o:['Uber、Lyft（美国）、Grab（东南亚）、Bolt（欧洲）','Didi（滴滴，主要在中国）','以上都用一个App','只能用出租车'],a:0,e:'各地主流网约车App不同：美国用Uber/Lyft，东南亚用Grab，欧洲多用Uber/Bolt，中东用Careem。建议出发前下载好！'},
  {c:'出国',q:'"Car rental"（租车）时，通常需要准备哪些证件？',o:['护照、国际驾照、信用卡（用于押金）','只需护照','身份证即可','只需信用卡'],a:0,e:'租车三件套：护照（身份证明）+ 国际驾照（中国驾照+公证翻译件，或正式国际驾照IDP）+ 信用卡（押金用）。部分国家可能还需国内驾照原件。'},
  {c:'出国',q:'看到路标"Dead End"，代表什么意思？',o:['此路不通/断头路（前方没有出口，需原路返回）','前方施工','道路合并','限速区'],a:0,e:'Dead End=此路不通，前方是死胡同，需要掉头。英式英语叫"No Through Road"或"Cul-de-sac"（法语借词，指死胡同小区）。'},
  {c:'出国',q:'在欧洲高铁上，"Seat reservation"是必须的吗？',o:['在许多欧洲高铁上（如TGV、Thalys），即使有通票也需要单独购买座位预约票','有通票就可以随便坐','只在头等舱需要预约','每次都免费自动预约'],a:0,e:'欧洲Rail Pass持有者在法国TGV、西班牙AVE、意大利Frecciarossa等高速列车上仍需额外购买seat reservation（座位预约），注意提前操作！'},
  {c:'出国',q:'"Platform"在火车站/地铁站中是指什么？',o:['月台/站台（上下车的地方）','候车大厅','检票口','行李寄存处'],a:0,e:'Platform=月台/站台。"The train departs from Platform 3."=列车从3号站台出发。London的King\'s Cross站还有著名的"Platform 9¾"（哈利波特！）'},
  {c:'出国',q:'在法国巴黎，地铁票"Carnet"原来是什么？现在替代它的是？',o:['Carnet原是10张地铁票的套票（已停售）；现在推荐购买Navigo Easy卡充值或Navigo月票','Carnet现在还在售，在所有地铁站均可购买','Carnet是周票','Carnet专指机场快线票'],a:0,e:'巴黎地铁已于2021年停售Carnet纸质套票，推荐使用Navigo Easy（可充值t+票）或Navigo Découverte（周/月卡）。注意机器操作语言可选英语！'}
);

// ──────────────────────────────────────────────────────────────
// 【4】购物英语 新增 ×15
// ──────────────────────────────────────────────────────────────
window.QB_EN_SHOPPING.push(
  {c:'出国',q:'收银台上写"No returns without receipt."，意思是？',o:['没有收据不能退货','没有收据不能结账','所有商品不可退换','收据可替代身份证'],a:0,e:'receipt=收据/小票，return=退货。在国外购物一定要保留收据，它是退换货的唯一凭证！'},
  {c:'出国',q:'你想问商品是否有其他颜色可选，应该说？',o:['Do you have this in a different color?','Is there a discount for this?','Can I return this?','Does this come in different sizes?'],a:0,e:'"Do you have this in ___?"可以替换颜色（blue, red, black）或尺码（large, small）。是购物时最实用的句型之一。'},
  {c:'出国',q:'"Black Friday"（黑色星期五）通常发生在什么时候？',o:['美国感恩节后的第一个星期五（11月下旬），是全年最大购物折扣日之一','12月25日圣诞节前一天','每月最后一个星期五','纯线上促销，没有具体日期'],a:0,e:'Black Friday（11月下旬）是美国最大的购物节，全美商场和网店大规模打折。现已扩展到全球，中国也有电商参与。'},
  {c:'出国',q:'你想比较两件商品哪个更值，应该问？',o:['Which one is better value for money?','Are both on sale?','Which is more popular?','Do you recommend either one?'],a:0,e:'value for money=性价比。"Which one gives better value for money?"=哪个性价比更好？这是购物时判断值不值的关键问题。'},
  {c:'出国',q:'"Warranty"（保修）在购买电子产品时有什么意义？',o:['在保修期内产品出现质量问题可免费维修或更换','是一种购物折扣','是强制购买的延保服务','仅在购买当天有效'],a:0,e:'warranty=保修，通常电子产品有1年保修。购买时问"Does it come with a warranty?"（带保修吗？）。注意：国外保修可能不涵盖中国地区！'},
  {c:'出国',q:'你在国外购物，看到标价"$29.99 + tax"，最终结账金额会是？',o:['比$29.99多，因为还要加税（美国大多数州有销售税）','恰好$29.99','比$29.99少（税已含在内）','取决于你的国籍'],a:0,e:'美国大多数州的商品标价不含税（tax=销售税，约5-10%），结账时才加上去。英国/欧洲标价通常已含VAT（增值税）。'},
  {c:'出国',q:'"Thrift store / Second-hand shop"是什么类型的店？',o:['二手店（出售二手衣物、家具等，价格低廉）','奢侈品折扣店','品牌工厂直销店','古董店（价格高）'],a:0,e:'Thrift store（美）/ Charity shop（英）=二手/旧货店，出售捐赠的二手衣物和物品，价格极低。对旅行者来说是淘特色旧货的好去处！'},
  {c:'出国',q:'"Flash sale"是什么类型的促销？',o:['限时闪购（在极短时间内提供大幅折扣，时间过了就结束）','全场五折大促','仅在App上的促销','VIP专属促销'],a:0,e:'Flash sale=限时闪购，通常只持续几小时甚至几分钟，折扣力度大。"This is a flash sale — only 30 minutes left!"=限时闪购，只剩30分钟！'},
  {c:'出国',q:'在超市结账，收银员说"Do you have a rewards card?"，是在问什么？',o:['你有没有会员积分卡（可以累积积分换取折扣）','你有没有信用卡','你是否享有员工折扣','你的购物总额是否达到满减标准'],a:0,e:'rewards card=会员积分卡，是商店的忠诚度计划。短期旅游通常没有，直接说"No, I don\'t."即可，不影响结账。'},
  {c:'出国',q:'"Outlet mall"（奥特莱斯）和普通商场有什么区别？',o:['Outlet出售过季或尾货，价格通常低于专卖店30-70%','Outlet比商场贵','Outlet只卖二手商品','Outlet是线上商场'],a:0,e:'Outlet mall=品牌折扣村/奥特莱斯，各大品牌开设工厂直销店，出售过季/尾货商品，折扣力度大。旅游购物的热门选择！'},
  {c:'出国',q:'你在商店看到"Final sale — no returns"，意思是？',o:['最终特卖，售出商品概不退换','最后一件，可以退换','特价促销，可在7日内退货','进入清仓季'],a:0,e:'Final sale=最终清仓特卖，这类商品通常不接受退换货（no returns）。购买前要三思，确认尺码和质量后再付款！'},
  {c:'出国',q:'你在市场上砍价，对方报价50美元，你觉得20美元合适，最佳策略是？',o:['从比目标价更低的价格开始还价，比如说"How about $15?"','直接说"I\'ll give you $20."','说"It\'s too expensive."然后离开（可能对方会叫你回来）','A和C都是有效策略'],a:3,e:'砍价技巧：①从低价开始还价②表现出不急着买的态度③准备离开有时会让卖家让步④最终双方在中间价位成交。在正规商场通常不能砍价，但在市场/景区可以试试。'},
  {c:'出国',q:'购物时看到"Buy one get one free"（BOGO），意思是？',o:['买一送一','买一打八折','满两件减一件价格','第二件半价'],a:0,e:'BOGO=Buy One Get One free=买一送一。"Buy 2 get 1 free"=买两送一。"Second one half price"=第二件半价。注意区分这些不同的促销方式！'},
  {c:'出国',q:'"Fitting room is at the back of the store."意思是？',o:['试衣间在店铺后方','收银台在店铺后方','出口在后方','仓库在后方'],a:0,e:'fitting room / changing room / dressing room=试衣间（美/英/通用）。"at the back=在后面"。试穿是购物前确认合身与否的重要步骤！'},
  {c:'出国',q:'看到商标"Made in ___"，这说明什么？',o:['这件商品在该国生产制造','这件商品在该国设计','这件商品只在该国销售','这是该国的特产'],a:0,e:'"Made in China/Japan/Italy..."=产地标签，说明这件商品在哪个国家生产。"Designed in Italy, Made in China"=意大利设计，中国制造，是常见的国际分工模式。'}
);

// ──────────────────────────────────────────────────────────────
// 【5】餐厅点餐英语 新增 ×15
// ──────────────────────────────────────────────────────────────
window.QB_EN_RESTAURANT.push(
  {c:'出国',q:'"I\'d like to make a reservation for 4 people at 7 PM."这句话用于什么场合？',o:['提前预订餐厅座位','在餐厅临时增加人数','询问菜品推荐','要求换桌子'],a:0,e:'reservation=预订，4 people=4位，7 PM=晚上7点。高档餐厅通常需要提前预订，电话或网上预订时用这个句型。'},
  {c:'出国',q:'你看不懂菜单上的某道菜，想了解食材，应该问？',o:['What\'s in this dish? / What are the ingredients?','Is this spicy?','Is this the chef\'s recommendation?','How much does this cost?'],a:0,e:'ingredients=食材/原料，"What\'s in this?"=这道菜里有什么？对于有食物过敏或饮食限制的人，询问食材非常重要。'},
  {c:'出国',q:'"Rare, medium rare, medium, medium well, well done"是描述什么的？',o:['牛排的熟度（一分熟到全熟）','咖啡的浓度','酒的年份等级','辣度等级'],a:0,e:'这五个词描述牛排熟度：Rare=一分熟（红色），Medium rare=三分熟（粉红），Medium=五分熟，Medium well=七分熟，Well done=全熟。'},
  {c:'出国',q:'服务员问"Still or sparkling water?"，他是在问什么？',o:['要无气泡水还是有气泡水','要热水还是冰水','要大杯还是小杯','要矿泉水还是自来水'],a:0,e:'Still water=无气泡水（普通水），Sparkling water=有气泡的碳酸水（如San Pellegrino）。欧洲很多餐厅不提供免费白水，需要点单。'},
  {c:'出国',q:'"May I have the menu, please?"和"Can we see the wine list?"分别是在要什么？',o:['菜单；酒单','饮料单；甜品单','账单；收据','推荐菜；招牌菜'],a:0,e:'menu=菜单，wine list=酒单。进入餐厅就座后，第一件事是要菜单。如果想喝酒，专门要wine list（有时和菜单分开）。'},
  {c:'出国',q:'"This dish is too salty / too sweet / too spicy."如何用英语表达，并要求厨房调整？',o:['This is too salty. Could you make it less salty next time? / Is there a milder version?','I don\'t like this.','Take this away.','I want my money back.'],a:0,e:'表达不满用"This is too ___."可以礼貌地说"Could it be made less spicy/salty?"但如果菜已做好，通常很难重做，更多是提供反馈。'},
  {c:'出国',q:'在美国餐厅，"Doggy bag"是什么意思？',o:['打包袋（把吃剩的食物带走，美国文化非常普遍）','给狗狗吃的食物','外卖袋','特价套餐'],a:0,e:'Doggy bag=打包袋，美国餐厅分量通常很大，打包剩菜非常普遍也被接受。"Can I get a doggy bag / to-go box?"=能帮我打包吗？'},
  {c:'出国',q:'"Happy Hour"通常在餐厅或酒吧指什么？',o:['特定时段内饮料或食物打折的促销活动（通常是下午4-7点）','开业特惠','节日特惠','全天特价'],a:0,e:'Happy Hour=欢乐时光，通常是傍晚时段（4-7PM），酒水饮料半价或买一送一。旅游时合理利用happy hour可以省不少钱！'},
  {c:'出国',q:'你进入一家餐厅发现是自助点餐的（self-service），以下哪项是对的？',o:['自己在柜台或机器点餐，取号或自取食物，通常不需要给小费','服务员还会来桌旁点餐','价格会比传统餐厅贵','自助点餐的餐厅质量更差'],a:0,e:'Self-service=自助服务餐厅（快餐/食堂模式），自己点餐取餐，通常不需要留小费（tip）。Full-service=全服务餐厅，有服务员，需要留小费（美国）。'},
  {c:'出国',q:'"Set menu / Prix fixe"是什么？',o:['固定套餐（包含前菜、主菜、甜点，价格固定，通常比单点便宜）','一种法式菜肴名称','仅限2人的情侣套餐','只有周末供应的菜单'],a:0,e:'Set menu（英）/ Prix fixe（法/美）=套餐，固定价格包含几道菜。餐厅通常提供午市套餐（Lunch special）性价比很高，比单点便宜20-30%。'},
  {c:'出国',q:'服务员说"Enjoy your meal!"，你应该回答？',o:['Thank you! / Thanks!','Yes, please.','I will.','Same to you.（如果对方也在吃饭）'],a:0,e:'"Thank you!"是最标准的回应。注意"Same to you"只有在对方也在享用美食时才合适，如果服务员没在吃东西说"same to you"会显得奇怪。'},
  {c:'出国',q:'餐厅账单上的"Gratuity"是指什么？',o:['小费（gratuity=tip的正式说法）','服务费','税费','餐厅优惠券'],a:0,e:'Gratuity=小费（更正式的表达）。"Gratuity included"=已包含小费（自动加到账单）。"Suggested gratuity: 18%"=建议小费比例。'},
  {c:'出国',q:'你有乳糖不耐症，在咖啡店应该怎么说？',o:['I\'m lactose intolerant. Do you have any dairy-free / plant-based milk options?','I don\'t like coffee.','Can I have decaf?','I prefer black coffee.'],a:0,e:'lactose intolerant=乳糖不耐，dairy-free=不含乳制品，plant-based milk=植物奶（oat milk燕麦奶、almond milk杏仁奶、soy milk豆奶）。'},
  {c:'出国',q:'"Bottomless brunch"是什么意思？',o:['无限续杯的早午餐（通常是固定价格，饮料可以无限续）','没有甜点的早餐','户外用餐的早午餐','非常丰盛的早餐'],a:0,e:'Bottomless brunch=无限续杯早午餐，英美都很流行，通常固定价格（£30-50）包含餐食+无限续杯特定饮料（如气泡酒、果汁）。周末最受欢迎！'},
  {c:'出国',q:'你在日本寿司店，"Omakase"是什么意思？',o:['厨师发办（由厨师决定当天菜单，通常是最高端的用餐体验）','素食套餐','外卖选项','儿童套餐'],a:0,e:'Omakase（おまかせ）=厨师发办，字面意思是"交给你了"。由主厨根据当季食材决定菜单，是日本料理最高端的用餐形式，价格通常较高。'}
);

// ──────────────────────────────────────────────────────────────
// 【6】紧急情况英语 新增 ×10
// ──────────────────────────────────────────────────────────────
window.QB_EN_EMERGENCY.push(
  {c:'出国',q:'你在酒店房间里发现有火灾迹象，最正确的做法是？',o:['立即按下火警报警器，沿紧急出口（不乘电梯）撤离，拨打消防电话','先收拾好行李再撤离','只通知隔壁房间','继续观察看看会不会自己灭'],a:0,e:'Fire emergency三原则：①触发警报②用安全出口楼梯（不要用电梯！）③拨打消防电话（美国911，英国999，欧盟112）。用毛巾捂住鼻子低姿势移动。'},
  {c:'出国',q:'"I think I\'ve been drugged."这句话用于什么紧急情况？',o:['怀疑自己被下迷药，需要立即告知警察或医疗人员','你在药店买药','你有药物过敏','你在询问处方'],a:0,e:'旅行中在陌生地方饮酒要警惕饮料被动手脚（drink spiking）。如感觉异常应立即告知同伴，前往安全地点并寻求医疗帮助。说"I think I was drugged."让急救人员立即明白情况。'},
  {c:'出国',q:'你在国外突发心脏病症状，打急救电话后，除了说清位置，还应该告知什么？',o:['症状（chest pain胸痛、difficulty breathing呼吸困难）、年龄、是否有已知心脏病病史','只说位置即可','先说你的国籍','先描述周围环境'],a:0,e:'急救时要说清：①位置②症状（"I have severe chest pain and difficulty breathing"）③年龄④病史。急救员会根据信息判断情况的严重性并安排相应资源。'},
  {c:'出国',q:'你在国外遭遇抢劫，事后应该优先做哪两件事？',o:['1.前往安全地点 2.立即报警（并索取报案回执，用于保险理赔）','1.追赶劫匪 2.发朋友圈','1.打电话给家人 2.继续旅游','1.回酒店 2.等待'],a:0,e:'遭遇抢劫后：①确保人身安全，远离现场 ②拨打报警电话，去警察局报案（案发时间/地点/经过）③获取Police Report（报案证明），是保险理赔的必要文件！'},
  {c:'出国',q:'"I\'m running out of medication."在医疗紧急情况中是指什么？',o:['我的药快用完了（需要在当地补充药物）','我对某种药过敏','我忘记服药了','我不需要药物治疗'],a:0,e:'长期用药者出境旅行必须携带足量药品，最好多备一些，并携带医生处方（英文版）。一旦药品不足，可前往当地诊所说这句话，医生可能开具临时处方。'},
  {c:'出国',q:'你的同伴突然晕倒，呼叫急救前你应该首先检查什么？',o:['检查呼吸（Look, Listen, Feel）和意识（能否唤醒），确认现场安全','先给他喝水','先发照片给急救','先检查行李是否安全'],a:0,e:'急救ABC：①Airway（气道通畅）②Breathing（呼吸）③Circulation（循环/心跳）。确认后立即拨打急救电话并按照调度员指示操作，必要时进行心肺复苏（CPR）。'},
  {c:'出国',q:'你在国外需要联系当地中国驻外机构，应该找哪种机构？',o:['大使馆（Embassy，在首都）或领事馆（Consulate，在其他大城市）','当地旅游局','中国商会','当地中餐馆'],a:0,e:'护照遗失/遭遇严重事故/被拘留时，立即联系中国驻当地大使馆（Embassy in capital）或领事馆（Consulate in other cities）。24小时领事保护热线：+86-10-12308。'},
  {c:'出国',q:'"I\'ve lost my credit card. I need to cancel it immediately."接下来应该怎么做？',o:['立即拨打银行卡背后的客服电话（全球热线）或通过银行App冻结卡片','等到回国再处理','在当地银行重新申请','通知酒店前台'],a:0,e:'丢失银行卡立即：①打卡背面客服热线（或银行App）挂失冻结 ②确认是否有可疑消费并报告 ③询问紧急补卡服务（部分银行可在海外紧急补卡）。VISA/Mastercard有全球紧急服务！'},
  {c:'出国',q:'旅行中遭遇自然灾害警报（如台风/地震），应该优先做什么？',o:['服从当地政府或酒店人员的安全指示，前往指定安全区域（Evacuation route=疏散路线）','继续观光','优先录视频发社交媒体','立即离开酒店自行寻找安全地点'],a:0,e:'灾难应对：①听从当地官方指示（emergency broadcast=紧急广播）②使用Evacuation route（疏散路线）③保持手机电量④联系家人报平安⑤联系中国驻当地大使馆。'},
  {c:'出国',q:'"My child is missing."在旅游景区应该怎么处理？',o:['立即告知景区安保人员，提供孩子照片和最后出现的位置，同时拨打当地警察电话','自己在景区随意寻找','等孩子自己回来','先拍发照片到网上求助'],a:0,e:'儿童走失（missing child）立即通知景区广播和安保人员，描述孩子的外貌特征（衣物颜色、身高、年龄）。大型景区有专属儿童走失服务台，不要独自乱跑！'}
);

// ──────────────────────────────────────────────────────────────
// 【7】亚洲热门目的地 新增 ×15
// ──────────────────────────────────────────────────────────────
window.QB_EN_GEO_ASIA.push(
  {c:'旅游',q:'日本京都最具代表性的传统建筑群之一"伏见稻荷大社"以什么闻名？',o:['绵延数公里的鸟居（Torii gates）走廊','樱花园和温泉','金碧辉煌的金阁寺','著名的茶道学校'],a:0,e:'Fushimi Inari Shrine（伏见稻荷大社）以数千座朱红色鸟居（Torii gates）排列成隧道而闻名，是京都最著名也是日本被拍摄最多的景点之一。'},
  {c:'旅游',q:'东南亚的"雨季"（monsoon season）通常是指什么？旅游时需要注意？',o:['每年约5-10月（各国略有不同），期间降雨频繁，旅游需带雨具，但酒店价格较低','雨季景色更美，推荐选择雨季旅游','雨季期间所有景点关闭','雨季与中国完全相同'],a:0,e:'东南亚雨季（Wet/Monsoon Season）约为5月至10月，泰国/越南南部/印尼等地降水多。旅游旺季（Dry Season=旱季）是11-4月，适合海滩旅游。'},
  {c:'旅游',q:'"Angkor Wat"（吴哥窟）位于哪个国家？',o:['柬埔寨（Cambodia）','越南（Vietnam）','泰国（Thailand）','缅甸（Myanmar）'],a:0,e:'Angkor Wat=吴哥窟，是世界上最大的宗教建筑，位于柬埔寨暹粒省，建于12世纪高棉帝国时期，是柬埔寨国旗上的标志性图案。'},
  {c:'旅游',q:'印度的"Taj Mahal"（泰姬陵）是哪位皇帝为谁建造的？',o:['莫卧儿皇帝沙贾汗为爱妻慕塔芝·玛哈尔建造（Shah Jahan for Mumtaz Mahal）','为母亲建造','作为皇宫','作为清真寺'],a:0,e:'泰姬陵（Taj Mahal）由沙贾汗皇帝为纪念爱妻慕塔芝·玛哈尔而建，是世界七大奇迹之一，被誉为"永恒爱情的象征"。位于阿格拉（Agra）。'},
  {c:'旅游',q:'香港的"The Peak"（太平山顶）最佳到访时间是？',o:['傍晚至夜晚，欣赏维多利亚港的夜景（被评为世界三大夜景之一）','清晨（日出时分）','正午（天气晴朗光线好）','任何时间都相同'],a:0,e:'太平山顶（Victoria Peak）夜景最为壮观，俯瞰维多利亚港（Victoria Harbour）灯光璀璨。傍晚时分乘坐山顶缆车（Peak Tram）上山，欣赏日落到夜景的变化。'},
  {c:'旅游',q:'"Maldives"（马尔代夫）最著名的住宿形式是什么？',o:['水上屋（Overwater bungalow/villa）——建在海面上的独立小屋','山间木屋','沙漠帐篷','传统民宿'],a:0,e:'马尔代夫Overwater bungalow（水上屋）是其标志性住宿，小屋建于清澈的印度洋海面上，浴室玻璃地板可直视海底。是蜜月旅行热门选择，但价格昂贵。'},
  {c:'旅游',q:'日本"艺妓"（Geisha）的英文正确写法是？',o:['Geisha（日文音译，正确）','Geiko（这是京都方言，也正确）','Geisha是正确的，Maiko=见习艺妓','以上均正确'],a:3,e:'Geisha=艺妓，Maiko=舞妓（见习艺妓）。在京都，艺妓通常叫Geiko（芸子），Maiko是学徒。在京都祗园区有机会看到她们，注意不要随意追拍打扰。'},
  {c:'旅游',q:'斯里兰卡（Sri Lanka）的"锡兰红茶"英文名是？',o:['Ceylon tea（以斯里兰卡旧称Ceylon命名）','Sri Lanka tea','Island tea','Indian tea'],a:0,e:'Ceylon=锡兰（斯里兰卡的英文旧称）。Ceylon tea（锡兰红茶）是世界最著名的红茶品种之一，产自努沃勒埃利耶（Nuwara Eliya）等高地茶园，到访斯里兰卡必体验茶园之旅。'},
  {c:'旅游',q:'尼泊尔首都"加德满都"的英文拼写是？',o:['Kathmandu','Kathmandue','Katmando','Kathmantu'],a:0,e:'Kathmandu（加德满都）是尼泊尔首都，是登山爱好者前往珠穆朗玛峰（Mount Everest）的出发基地。Everest Base Camp（EBC）大本营徒步是世界级的户外体验。'},
  {c:'旅游',q:'越南"会安古镇"的英文名称是？它因何而出名？',o:['Hoi An；以保存完好的15-19世纪贸易港口古镇、五彩灯笼和裁缝店闻名','Ho Chi Minh City；以战争历史博物馆闻名','Hanoi；以还剑湖和旧街区闻名','Da Nang；以海滩著名'],a:0,e:'Hoi An Ancient Town（会安古镇）是UNESCO世界遗产，以古色古香的黄色建筑、河灯、定制旗袍/西服（24小时裁缝服务）闻名，是越南最上相的旅游地。'},
  {c:'旅游',q:'菲律宾的"El Nido"（爱妮岛）位于哪个岛屿？以什么著名？',o:['位于巴拉望岛（Palawan）；以石灰岩峭壁、碧绿潟湖和海岛跳岛游著名','位于宿雾（Cebu）；以潜水著名','位于薄荷岛（Bohol）；以眼镜猴著名','位于长滩岛（Boracay）；以白沙滩著名'],a:0,e:'El Nido在Palawan（巴拉望）北端，以石灰岩悬崖、神秘潟湖（Secret Lagoon / Big Lagoon）和Island Hopping（跳岛游）闻名，被多次评为全球最美海滩目的地之一。'},
  {c:'旅游',q:'在以色列，"Dead Sea"（死海）有什么独特的旅游体验？',o:['极高盐分（约34%）使人自然漂浮，游客在海面上读报纸是经典打卡照','可以在死海底部行走','死海有著名的珊瑚礁潜水点','死海是世界上最大的淡水湖'],a:0,e:'Dead Sea（死海）是世界上海拔最低的水域，含盐量约为普通海水的10倍，人体在水中自然浮起无法下沉。富含矿物质的黑泥（Dead Sea mud）还被认为有护肤功效。'},
  {c:'旅游',q:'中国的"万里长城"在英文中是什么？',o:['The Great Wall of China','The Long Wall','China\'s Ancient Wall','The Ming Dynasty Wall'],a:0,e:'The Great Wall of China（中国长城）是世界著名文化遗产，全长约21196公里。北京近郊的慕田峪（Mutianyu）和八达岭（Badaling）是最受外国游客欢迎的段落。'},
  {c:'旅游',q:'泰国清迈（Chiang Mai）以什么旅游活动著名？',o:['大象保护营（Ethical Elephant Sanctuary）、寺庙群、夜市和登山徒步','潜水和海岛游','高楼夜景和购物中心','古代战场遗址'],a:0,e:'Chiang Mai=清迈，泰国北部文化古都。以数百座佛寺（如素帖寺Doi Suthep）、伦理大象营（不骑象）、夜市（周六/周日步行街）、手工艺品闻名。'},
  {c:'旅游',q:'去日本旅游，以下哪个APP最适合查询实时公共交通信息？',o:['Google Maps（谷歌地图）、Japan Official Travel App、HyperDia（火车换乘查询）','Baidu Maps（在日本也有信号）','只能购买纸质地图','滴滴出行'],a:0,e:'日本旅游交通工具：①Google Maps实时导航 ②HyperDia专门用于日本火车/新干线换乘查询 ③Google Map在日本准确性极高。Suica/Pasmo卡配合地图是最完美的搭配。'}
);

// ──────────────────────────────────────────────────────────────
// 【8】欧洲经典目的地 新增 ×15
// ──────────────────────────────────────────────────────────────
window.QB_EN_GEO_EUROPE.push(
  {c:'旅游',q:'"The Colosseum"（罗马斗兽场）位于哪个城市？建于哪个朝代？',o:['意大利罗马；建于公元70-80年（罗马帝国韦斯巴芗和提图斯皇帝时期）','希腊雅典；建于公元前5世纪','土耳其伊斯坦布尔；建于拜占庭帝国','西班牙马德里；建于中世纪'],a:0,e:'The Colosseum（斗兽场）是罗马最具代表性的地标，建于公元72年，能容纳5-8万观众，曾用于角斗士比赛。是世界七大奇迹（现代版）之一。'},
  {c:'旅游',q:'英国的"Stonehenge"（巨石阵）在哪里？有什么神秘之处？',o:['位于英格兰威尔特郡（Wiltshire）；建造目的和方法至今成谜，被认为与天文/宗教仪式有关','位于苏格兰高地；是罗马人建造的','位于威尔士；是维京人的祭坛','位于伦敦郊外；是中世纪城堡遗址'],a:0,e:'Stonehenge（巨石阵）约建于公元前3000-2000年，巨石来自约250公里外的威尔士。其精确的天文对准（夏至日出方向）令现代人费解，是英国最神秘的史前遗迹。'},
  {c:'旅游',q:'去冰岛旅游，观看"Northern Lights"（北极光）的最佳时间是？',o:['9月至3月（秋冬季，漫长黑夜期间），远离城市光污染的黑暗户外','6-8月的夏季（午夜太阳期间）','全年任意时间均可看到','只有在首都雷克雅未克才能看到'],a:0,e:'Aurora Borealis（北极光）观测需要：①黑暗的天空（9-3月）②晴朗无云的天气③太阳活动强（KP指数3+）④远离城市灯光。冰岛9月至3月是观测最佳季节。'},
  {c:'旅游',q:'瑞士以什么旅游体验最著名？用英语怎么描述？',o:['阿尔卑斯山滑雪（Alpine skiing）、徒步（hiking）、欣赏雪山风光（scenic mountain views）、巧克力和钟表','地中海沿岸阳光海滩','古代遗址和博物馆','热带雨林探险'],a:0,e:'Switzerland（瑞士）=多语言国家（德/法/意/罗曼什语），以Alps（阿尔卑斯山）、Swiss chocolate（瑞士巧克力）、Swiss watches（瑞士手表）、Zurich（苏黎世）、Geneva（日内瓦）著名。'},
  {c:'旅游',q:'"Fjord"（峡湾）是哪个国家的代表性地貌？',o:['挪威（Norway）；世界上峡湾最多最壮观的国家','瑞典','芬兰','丹麦'],a:0,e:'Fjord=峡湾，是冰川运动侵蚀形成的深长狭窄海湾，峭壁高耸。挪威盖朗厄尔峡湾（Geirangerfjord）和纳柔依峡湾（Nærøyfjord）是UNESCO世界遗产，被誉为最壮美的自然景观。'},
  {c:'旅游',q:'葡萄牙里斯本（Lisbon）特有的传统音乐形式是什么？',o:['法多（Fado）；忧郁而深情的传统歌谣，已被列入UNESCO非物质文化遗产','弗拉门戈（Flamenco）','法多是西班牙的，葡萄牙没有特色音乐','桑巴（Samba）'],a:0,e:'Fado（法多）=葡萄牙传统音乐，以吉他伴奏、忧郁哀愁的歌声著称，主题多为命运、思乡、爱情。里斯本的Alfama区（阿法玛）是体验法多的最佳场所。'},
  {c:'旅游',q:'捷克首都布拉格（Prague）著名的天文钟叫什么？',o:['Astronomical Clock / Orloj（奥洛穆茨天文钟的布拉格版本）','Big Ben','Eiffel Clock','Prague Tower Clock'],a:0,e:'Prague Astronomical Clock（布拉格天文钟/Pražský Orloj）建于1410年，位于旧市政厅（Old Town Hall），每小时整点有精彩的木偶报时表演，是布拉格最热门的打卡地。'},
  {c:'旅游',q:'英国"下午茶"（Afternoon Tea）起源于哪个年代？包含哪些内容？',o:['维多利亚时代（19世纪）；通常包括三层架点心（三明治、司康饼、蛋糕）配红茶','20世纪50年代；只包含红茶和饼干','中世纪；包含啤酒和面包','现代创造；只有在伦敦才能体验'],a:0,e:'Afternoon Tea（下午茶）起源于19世纪英国贵族，传统包括：三层架（three-tier stand）装的finger sandwiches（小三明治）、scones（司康）配clotted cream和jam，以及各种小蛋糕。'},
  {c:'旅游',q:'荷兰阿姆斯特丹的"Anne Frank House"（安妮·弗兰克故居）有什么历史意义？',o:['二战时期犹太女孩安妮·弗兰克藏身于此躲避纳粹迫害，并在此完成日记','是荷兰王室的旧居','是梵高的出生地','是历史上著名的秘密集会场所'],a:0,e:'Anne Frank House=安妮之家，是二战期间犹太少女安妮·弗兰克（Anne Frank）及家人躲藏2年的地方。她在此完成了《安妮日记》（The Diary of a Young Girl），后被抓并死于集中营。必须提前网上预约！'},
  {c:'旅游',q:'土耳其伊斯坦布尔的"圣索菲亚大教堂"（Hagia Sophia）有什么特殊的历史？',o:['历经教堂→清真寺→博物馆→清真寺的历史变迁，是东西文明交汇的象征','一直是基督教大教堂，从未改变','是奥斯曼帝国专门建造的清真寺','是现代建筑，20世纪才建成'],a:0,e:'Hagia Sophia（圣索菲亚大教堂）建于537年，曾是拜占庭帝国大教堂，1453年奥斯曼帝国占领后改为清真寺，1934年改为博物馆，2020年再次改回清真寺。是东西方文明交汇的建筑奇迹。'},
  {c:'旅游',q:'去德国慕尼黑，"Oktoberfest"（啤酒节）通常在什么时候举行？',o:['每年9月下旬至10月上旬（约2-3周），是全球最大的民间节庆之一','每年10月全月','每年12月圣诞节期间','每年7月夏季'],a:0,e:'Oktoberfest（慕尼黑啤酒节）通常9月第三个周六开幕，持续约16-18天至10月第一个周日。每年吸引约600万游客，需提前预订帐篷里的座位，非常热闹！'},
  {c:'旅游',q:'波兰克拉科夫（Kraków）附近的"奥斯维辛集中营"英文名是？',o:['Auschwitz-Birkenau Concentration Camp','Dachau Camp','Buchenwald Camp','Warsaw Camp'],a:0,e:'Auschwitz-Birkenau（奥斯维辛-比克瑙）是二战期间纳粹德国在波兰建立的最大规模集中营，约110万人（主要是犹太人）在此遇难，现为UNESCO世界遗产，提醒世人铭记历史。'},
  {c:'旅游',q:'"The Louvre"（卢浮宫）在哪个城市？收藏了哪幅最著名的画作？',o:['法国巴黎；收藏了达芬奇的《蒙娜丽莎》（Mona Lisa）','英国伦敦；收藏了《星夜》','意大利罗马；收藏了米开朗基罗壁画','西班牙马德里；收藏了毕加索《格尔尼卡》'],a:0,e:'The Louvre（卢浮宫）是世界最大博物馆，参观人数世界第一，收藏超过38万件艺术品。镇馆之宝是达芬奇的Mona Lisa（蒙娜丽莎），以及古希腊雕塑《断臂维纳斯》（Venus de Milo）。'},
  {c:'旅游',q:'去西班牙巴塞罗那旅游，"La Sagrada Família"（圣家族大教堂）的特别之处是？',o:['由高迪（Gaudí）设计，1882年开始建造，至今仍未完工，预计2026年竣工','是世界上最古老的教堂','由米开朗基罗设计','已在2010年正式完工'],a:0,e:'Sagrada Família是西班牙建筑师高迪（Antoni Gaudí）的毕生杰作，自1882年建造至今超过140年，以独特的有机自然主义风格著称，已被列为UNESCO世界遗产，是巴塞罗那必访地标。'},
  {c:'旅游',q:'爱尔兰都柏林（Dublin）著名的"吉尼斯世界纪录"总部在这里吗？以下正确的是？',o:['吉尼斯世界纪录的出版商源于爱尔兰，Guinness Storehouse（吉尼斯黑啤工厂）在都柏林是著名旅游景点','爱尔兰没有任何与吉尼斯相关的景点','吉尼斯总部在伦敦','吉尼斯是德国啤酒品牌'],a:0,e:'Guinness（吉尼斯）是爱尔兰最著名的黑啤品牌，创立于1759年。Guinness Storehouse在都柏林St. James\'s Gate，是爱尔兰参观人数最多的景点，顶层有360度都柏林全景！'}
);

// ──────────────────────────────────────────────────────────────
// 【9】美洲及大洋洲 新增 ×12
// ──────────────────────────────────────────────────────────────
window.QB_EN_GEO_AMERICAS.push(
  {c:'旅游',q:'美国纽约的"Times Square"（时代广场）位于哪个区？',o:['曼哈顿中城（Midtown Manhattan）','布鲁克林（Brooklyn）','皇后区（Queens）','布朗克斯（Bronx）'],a:0,e:'Times Square位于曼哈顿中城，以巨型电子广告牌、百老汇剧院、24小时人流不息著名。每年新年倒计时的水晶球降落（Ball Drop）是全球最知名的跨年活动之一。'},
  {c:'旅游',q:'加拿大的"Niagara Falls"（尼亚加拉大瀑布）在哪两个国家/省州的交界处？',o:['加拿大安大略省（Ontario）和美国纽约州（New York）交界','加拿大和墨西哥交界','加拿大不列颠哥伦比亚省和美国华盛顿州交界','位于加拿大内陆'],a:0,e:'Niagara Falls横跨美加边境，由马蹄瀑布（Horseshoe Falls，加拿大侧，更壮观）和美国瀑布组成。加拿大侧视角更好，推荐乘坐"雾中少女号（Maid of the Mist）"游船近距离体验。'},
  {c:'旅游',q:'巴西里约热内卢（Rio de Janeiro）著名的"基督像"的正式名称是？',o:['Christ the Redeemer（救世基督像）','Jesus Statue','Rio Christ','Corcovado Cross'],a:0,e:'Christ the Redeemer（救世基督像）高38米，建于1931年，俯瞰里约热内卢，是世界新七大奇迹之一。每年前来拍照的游客达到数百万。'},
  {c:'旅游',q:'秘鲁的"Machu Picchu"（马丘比丘）是哪个古代文明的遗址？',o:['印加文明（Inca Civilization），约建于15世纪','玛雅文明（Maya）','阿兹特克文明（Aztec）','科尔特斯文明'],a:0,e:'Machu Picchu（马丘比丘）是印加帝国（Inca Empire）的遗址，约建于1450年，位于安第斯山脉高处（海拔2430米），1911年被美国探险家重新发现，是南美洲最著名的旅游目的地。'},
  {c:'旅游',q:'澳大利亚"乌鲁鲁"（Uluru/Ayers Rock）对当地原住民有什么特殊意义？',o:['是阿南古（Anangu）原住民的圣地，现已禁止攀爬以示尊重','只是普通的旅游景点','是澳大利亚最高的山峰','是澳大利亚国家公园的最大停车场'],a:0,e:'Uluru（乌鲁鲁/艾尔斯岩）是澳大利亚中部的标志性红色岩石，对阿南古原住民具有深厚的宗教和文化意义。2019年起正式禁止游客攀爬，以尊重原住民文化。观赏日出日落变色是最佳体验。'},
  {c:'旅游',q:'墨西哥的"Day of the Dead"（亡灵节）是一种什么节日？',o:['每年11月1-2日，用以纪念已故亲人的墨西哥传统节日，色彩丰富，充满欢乐而非悲伤','全年最大的购物节','与万圣节（Halloween）完全相同','是天主教圣诞节前的斋戒期'],a:0,e:'Día de los Muertos（亡灵节）是墨西哥最重要的传统节日，人们制作彩色糖骷髅（Calaveras）、建造祭坛（Ofrendas）、前往墓地献花，被列入UNESCO人类非物质文化遗产。'},
  {c:'旅游',q:'加拉帕戈斯群岛（Galapagos Islands）属于哪个国家？以什么著名？',o:['厄瓜多尔（Ecuador）；达尔文在此研究进化论，拥有独特动植物（如巨型陆龟、海鬣蜥）','秘鲁；以海豚著名','智利；以火山地貌著名','巴西；以热带雨林著名'],a:0,e:'Galapagos Islands=加拉帕戈斯群岛，隶属厄瓜多尔，是达尔文提出进化论的灵感来源。这里有世界上独一无二的动物（Giant Tortoise巨龟、Marine Iguana海鬣蜥等），是自然观察者的天堂。'},
  {c:'旅游',q:'美国"Route 66"（66号公路）为什么对旅行者有特殊意义？',o:['是美国最著名的公路旅行（road trip）线路，连接芝加哥至洛杉矶，全长约3900公里，象征美国自由精神','是美国最高速限的公路','是只供摩托车行驶的专用道','是美国第一条铁路线'],a:0,e:'Route 66（66号公路）是美国文化标志，被称为"Mother Road（母亲之路）"，从芝加哥穿越8个州至洛杉矶。沿途有复古小镇、经典Diner（美式餐厅）、西部峡谷，是自驾旅行的终极梦想线路。'},
  {c:'旅游',q:'新西兰"霍比特人村"（Hobbiton）在哪里？是什么？',o:['位于北岛玛塔玛塔（Matamata）附近，是《指环王》和《霍比特人》的拍摄场景，现为旅游景点','位于南岛基督城，是真实的中世纪村庄','是新西兰原住民的传统部落','是奥克兰郊外的主题公园'],a:0,e:'Hobbiton Movie Set在新西兰北岛，是彼得·杰克逊拍摄《指环王》系列的取景地，保留了44个霍比特洞穴和Green Dragon酒馆，是全球影迷的朝圣地，需提前预约。'},
  {c:'旅游',q:'阿根廷的"Patagonia"（巴塔哥尼亚）是什么类型的旅游目的地？',o:['地球上保存最完好的荒野地区之一，以壮丽的冰川、山峰（如菲茨罗伊峰）和无人荒野著名','热带雨林目的地','阿根廷最繁华的城市区','以葡萄酒庄园著名'],a:0,e:'Patagonia横跨阿根廷和智利南部，以Torres del Paine（托雷斯德尔潘恩）国家公园、Perito Moreno冰川、极端天气和绝世风景著名，是户外探险爱好者的终极目的地。'},
  {c:'旅游',q:'夏威夷（Hawaii）属于美国，但地理上位于哪里？为什么气候独特？',o:['位于太平洋中部，是美国唯一的热带州，受太平洋暖流影响，全年温暖湿润','位于大西洋中部','位于墨西哥湾','在美国大陆西海岸附近'],a:0,e:'Hawaii（夏威夷）是美国第50个州，位于太平洋中部（北纬20度）。由8个主要岛屿组成，以火山地貌（Kilauea活火山）、冲浪（北岸著名大浪）、草裙舞（Hula）著名。'},
  {c:'旅游',q:'古巴（Cuba）的首都是？对中国旅客有什么签证政策？',o:['哈瓦那（Havana）；中国公民可免签入境古巴（截至2024年）','圣地亚哥；需要提前申请签证','哈瓦那；需要申根签证','圣克拉拉；需要通过美国入境'],a:0,e:'Havana（哈瓦那）是古巴首都，以彩色老爷车（vintage cars）、殖民地建筑、雪茄（cigars）和朗姆酒（rum）著名。中国公民曾享有免签政策，但请出发前核查最新政策，因政策可能变化。'}
);

// ──────────────────────────────────────────────────────────────
// 【10】旅行高频词汇 新增 ×15
// ──────────────────────────────────────────────────────────────
window.QB_EN_VOCAB_TRAVEL.push(
  {c:'词汇',q:'"Wanderlust"是什么意思？',o:['对旅行的强烈渴望/旅行癖（来自德语）','旅行的疲惫感','迷路的状态','对家乡的思念'],a:0,e:'Wanderlust（源自德语Wandern旅行+Lust渴望）=旅行癖/对旅行的强烈渴望。现在是英语中常见的社交媒体标签和旅行文化词汇。#Wanderlust'},
  {c:'词汇',q:'"Bucket list"在旅行中是什么意思？',o:['人生必做清单（死前想完成的事和去的地方）','行李打包清单','旅行购物清单','旅行禁忌清单'],a:0,e:'Bucket list（来自短语"kick the bucket"=死）=人生清单，指死前必做的事。"This place is on my bucket list."=这个地方在我的人生清单上。旅行版通常是"must-visit destinations"。'},
  {c:'词汇',q:'"Off the beaten path"是什么意思？',o:['不走寻常路，前往非主流、鲜有游客的地方','走错方向/迷路','在热门景点排队','徒步登山'],a:0,e:'"Off the beaten path/track"=远离常规旅游路线，探索冷门目的地。这类旅行更原汁原味，避开旅游人潮，但需要更多准备和当地知识。'},
  {c:'词汇',q:'"Airbnb"是什么类型的住宿方式？',o:['民宿/短期出租（通过平台在当地居民家中或整套公寓住宿）','廉价酒店连锁','机场内的商务休息室','背包客旅舍'],a:0,e:'Airbnb是全球最大的民宿平台，可以租住当地居民的房间或整套公寓，通常比同等酒店便宜，更有生活感，适合长期旅居或家庭出游。'},
  {c:'词汇',q:'"Visa on arrival"（落地签）是什么意思？',o:['抵达目的地机场后在入境处直接申请签证，无需提前办理','预先在大使馆申请的签证','电子签证','不需要任何签证'],a:0,e:'Visa on arrival=落地签，在目的地机场的签证窗口办理，通常需要填表、照片和费用。比提前申请更方便，但要确认该国是否对中国公民开放落地签！'},
  {c:'词汇',q:'"Hostel dorm"是什么住宿类型？',o:['青年旅舍宿舍（多人共用一个房间，通常4-12人，是最便宜的住宿方式）','家庭套房','豪华双人间','服务式公寓'],a:0,e:'Hostel dorm（宿舍床位）=在青年旅舍（Hostel）中与陌生人同住一个多人间，有各自的床位（通常是双层床/bunk bed），是背包旅行中最省钱的住宿方式。'},
  {c:'词汇',q:'"Couchsurfing"是什么旅行方式？',o:['一种通过同名平台与当地人连接，免费借住在他们家沙发上的旅行方式','乘坐沙发车旅行','豪华轮船旅行','一种冲浪运动'],a:0,e:'Couchsurfing=沙发客文化，旅行者通过Couchsurfing.com平台找当地人免费提供沙发/房间住宿，以文化交流为目的。已成为全球数百万背包客连接当地文化的方式。'},
  {c:'词汇',q:'"Carbon footprint"（碳足迹）和旅行有什么关系？',o:['旅行（尤其是飞行）会产生大量碳排放，可以通过购买碳抵消（carbon offset）减少环境影响','碳足迹只和工厂有关，和旅行无关','步行旅游会增加碳足迹','碳足迹是旅行中的一种消费积分'],a:0,e:'Aviation（航空业）是重要的碳排放来源。Carbon offset（碳抵消）=通过购买可再生能源项目或植树配额来中和旅行产生的碳排放。可持续旅行的重要实践之一。'},
  {c:'词汇',q:'"Digital nomad"是什么类型的旅行者？',o:['数字游民（通过远程工作，在世界各地工作与旅行的人）','专门拍摄数字照片的旅行者','只乘坐数字化交通工具的旅行者','使用电子地图的旅行者'],a:0,e:'Digital nomad=数字游民，利用互联网和远程工作，可以在世界任何地方边工作边旅行。Bali（巴厘岛）、Chiang Mai（清迈）、Lisbon（里斯本）是全球最热门的数字游民聚集地。'},
  {c:'词汇',q:'"Ecotourism"（生态旅游）的核心理念是什么？',o:['以最小环境影响游览自然地区，支持当地保护工作和社区经济的旅游方式','乘坐电动车辆的旅游','只前往森林和海洋的旅游','植物园参观活动'],a:0,e:'Ecotourism=生态旅游，强调：①保护自然环境 ②尊重当地文化 ③使旅游收益惠及当地社区。Costa Rica（哥斯达黎加）、Galapagos是全球生态旅游标杆目的地。'},
  {c:'词汇',q:'"Travel advisory"（旅行预警）是什么？',o:['政府发出的旅行安全建议，警告公民前往特定国家/地区的风险等级','旅行社的促销广告','旅行博主的目的地推荐','航空公司的行李规定'],a:0,e:'Travel advisory（旅行预警/提示）=一国政府对本国公民发出的出境旅行安全建议。中国外交部的"领事服务网"提供各国安全形势和旅行提示，出发前务必查看！'},
  {c:'词汇',q:'"Time zone"（时区）对国际旅行者的实际影响是什么？',o:['跨时区旅行需要调整手表/手机时间，并注意预订机票/会议时的时间换算，以及可能产生时差（jet lag）','时区只对飞行员有影响','所有手机会自动正确换算任何时区','时区差异不影响旅行'],a:0,e:'国际旅行常见时区问题：①飞机餐时间②转机时间换算③和国内家人联系的时差④酒店早餐时间。iPhone/Android会自动更换时区，但定好的行程要注意是哪个时区的时间。'},
  {c:'词汇',q:'"Customs declaration"（海关申报）是什么程序？',o:['入境时向海关申报携带的物品（尤其是现金、食品、超额商品），据实填写海关申报表','在机场购买商品的收据','申请免税商品的程序','出境时办理行李托运的手续'],a:0,e:'海关申报（Customs declaration）是入境的必要程序。超过免税额度（通常5000元人民币以上商品）必须申报。部分食品、动植物产品、现金超过一定金额（如美国$10,000）也必须申报，否则可能被没收甚至罚款。'},
  {c:'词汇',q:'"House rules"在Airbnb民宿中是指？',o:['房东制定的住宿规则（如不允许吸烟、禁止宠物、几点后禁止喧哗等）','租金计算方法','取消预订政策','房间内的设施清单'],a:0,e:'House rules=住宿规定，是Airbnb房东为房客设定的规则，在预订时必须同意。常见规定：No smoking（禁烟）、No pets（禁止宠物）、Quiet hours（安静时间）。违反可能被要求退出！'},
  {c:'词汇',q:'"Travel insurance excess/deductible"（自付额）是什么意思？',o:['在保险公司理赔时，你自己需要承担的那部分费用（超过这个金额保险公司才开始赔）','保险公司赔付的最高金额','购买旅行保险需要支付的额外费用','旅行结束后的退保金额'],a:0,e:'Excess/Deductible=免赔额，例如你的手机摔碎价值500美元，保险有$100免赔额，则保险赔$400。免赔额越高，保费通常越低，但出险时自付越多。购买前要仔细对比！'}
);

// ──────────────────────────────────────────────────────────────
// 【11】日常生活词汇 新增 ×12
// ──────────────────────────────────────────────────────────────
window.QB_EN_VOCAB_DAILY.push(
  {c:'词汇',q:'"Tap water"在哪些国家可以直接饮用？',o:['大多数西欧、北欧、北美、澳大利亚、新西兰、日本的自来水可以直接饮用','所有国家的自来水均可直接饮用','只有法国和德国可以','只有购买矿泉水才安全'],a:0,e:'发达国家（英美日澳等）自来水经严格处理，可以直接饮用。东南亚、南亚、非洲、中南美洲等地建议饮用瓶装水（bottled water）。旅游前查清目的地的饮水安全情况！'},
  {c:'词汇',q:'"SIM card"（手机SIM卡）在国外旅游时的作用是什么？',o:['使用当地号码和数据流量，通话和上网更便宜，不产生高额国际漫游费','只能用于打电话，不能上网','替代护照作为身份证明','替代当地货币付款'],a:0,e:'买当地SIM卡是最划算的联网方式。机场或便利店（如日本7-Eleven）可以买到预付费SIM（prepaid SIM card），内含本地流量。只需把手机里的中国卡换出来，插入当地SIM即可。'},
  {c:'词汇',q:'"Laundromat / Launderette"是什么地方？',o:['自助洗衣店（投币式洗衣机/烘干机，按次付费）','酒店的洗衣服务','干洗店','布料店'],a:0,e:'Laundromat（美）/ Launderette（英）=自助洗衣店，可以自己投币使用洗衣机和烘干机，比酒店洗衣便宜很多。长途旅行时自助洗衣是节省旅行经费的好方法。'},
  {c:'词汇',q:'在超市，"Aisle"（走道）标牌的作用是？',o:['帮助找到特定商品的区域（如"Aisle 5: Beverages"=第5走道是饮料区）','超市促销区域','收银台编号','停车场区域编号'],a:0,e:'超市Aisle=货架走道，通常编号并标明商品类别。"Which aisle is the pasta in?"=意面在哪个走道？美国大型超市动辄数十条走道，熟悉aisle编号能节省大量时间。'},
  {c:'词汇',q:'"Public holiday"（公众假日）对旅行有什么影响？',o:['景点/商店可能关闭或拥挤，交通可能受影响，建议提前查询目的地的公众假日','没有任何影响','公众假日景点全部免票','公众假日所有商店延长营业时间'],a:0,e:'每个国家的公众假日（Public Holiday / Bank Holiday）不同。出行前查清目的地的假日，避免景点关闭或订不到座位。圣诞节/新年期间欧美很多商铺关门，要提前备好食物和现金。'},
  {c:'词汇',q:'"Self-checkout"（自助结账）在超市中如何使用？',o:['自己扫描商品条形码，系统计算总价，用信用卡或手机支付，无需排队等收银员','需要收银员协助才能使用','只接受现金','只适用于会员顾客'],a:0,e:'Self-checkout=自助收银机，越来越多超市（Walmart、Tesco、Woolworths等）提供。扫描商品→放到秤上确认→结账。不会操作可以按"Help"按钮，会有工作人员协助。'},
  {c:'词汇',q:'"Yield sign"、"Stop sign"、"Speed limit sign"分别用于什么情况？',o:['让行（三角或倒三角标志）、停车（八角形红色STOP）、限速（圆形显示数字）','三者都是禁止通行','都是建议性标志无需强制遵守','只适用于高速公路'],a:0,e:'驾车旅行必须认识：Yield（让行）=减速礼让，不要求完全停车；Stop（停车）=必须完全停车；Speed Limit 65（限速65英里/小时）=强制执行，超速罚款很重！'},
  {c:'词汇',q:'"Voltage"（电压）和"Frequency"（频率）对携带的电器有什么影响？',o:['不同国家电压/频率不同（中国220V/50Hz，美国110V/60Hz），不兼容的电器可能被烧毁','所有现代电器都支持全球电压，无需担心','只有电脑需要注意电压','只有电压重要，频率无所谓'],a:0,e:'出国用电注意：①查看充电器/电器铭牌，如标"100-240V"则自动适配全球电压，只需转换插头②单一电压电器（如仅写"220V"）在低压国家不可用③大功率电器（吹风机/电饭煲）需要电压转换器（Voltage Converter）。'},
  {c:'词汇',q:'"Prescription"（处方）和"Over-the-counter"（非处方）药物的区别是？',o:['处方药需要医生开具才能购买；非处方药（OTC）无需处方可直接在药店购买','处方药比非处方药更贵','非处方药更有效','处方药在所有国家都一样'],a:0,e:'出国旅行携带处方药时，要同时带上医生开具的英文处方（prescription），以便在海关检查时证明合法性。部分中国常见处方药（如含可待因的止咳药）在其他国家可能是管制品，携带前要查清！'},
  {c:'词汇',q:'"Tipping culture"（小费文化）——在哪些具体场景下通常需要给小费？',o:['餐厅服务员（15-20%）、出租车司机（10-15%）、酒店行李员（$1-2/件）、美发（15-20%）','所有购物场景','超市收银员','自动售货机'],a:0,e:'美国小费参考标准：餐厅15-20%（好服务20%+）；出租车/Uber 10-15%；行李员每件行李$1-2；酒店管家$2-5/天；理发15-20%。很多收款机会直接弹出推荐小费界面。'},
  {c:'词汇',q:'"Rental car insurance"（租车保险）有哪些常见类型？',o:['CDW/LDW（车辆损失险）、Liability（责任险）、PAI（人身意外险）、PEC（个人物品险）','只有一种全险','信用卡自带保险不需要额外购买（部分高端信用卡确实包含租车保险）','租车不需要保险'],a:0,e:'租车保险重要提示：①CDW/LDW（碰撞损失豁免险）最重要，建议购买②部分高端信用卡（Visa Signature/Mastercard World Elite）自带租车保险，可以不用单独购买③仔细阅读自付额（excess）条款。'},
  {c:'词汇',q:'"Jet bridge / Aerobridge / Jetway"是机场的什么设施？',o:['廊桥（连接机场与飞机舱门的密封通道，直接登机不需在露天走）','机场内的小型电车','行李传送带','登机口的电子门禁'],a:0,e:'Jet bridge（廊桥）=机场与飞机之间的密封通道，可以直接登机不用走露天停机坪。没有廊桥时要乘坐摆渡车（shuttle bus/airport bus）到飞机旁边从舷梯（air stairs）登机。'}
);

// ──────────────────────────────────────────────────────────────
// 【12】旅行实用语法 新增 ×15
// ──────────────────────────────────────────────────────────────
window.QB_EN_GRAMMAR.push(
  {c:'语法',q:'"Have you ever been to...?"和"Have you been to...?"的区别是？',o:['加ever（曾经）更强调"人生中是否经历过"，语气更加强调；两者含义相似，ever使问题更自然','Ever使问题变成否定','两者是完全不同的时态','Have been只用于书面语'],a:0,e:'"Have you ever been to Japan?"=你曾经去过日本吗？（强调人生经历）"Have you been to Japan?"=你去过日本吗？（较中性）两者都用现在完成时（present perfect tense）。'},
  {c:'语法',q:'"How long does it take to get there?"是什么意思？如何回答？',o:['"到那里需要多长时间？"；回答格式：It takes about 30 minutes / 2 hours.','到那里要花多少钱？','那里的历史有多悠久？','到那里有多难？'],a:0,e:'"How long does it take?"是询问时间的固定句型。回答用"It takes + 时间"。"It takes about an hour by subway."=地铁大约一小时。非常实用的旅行问句！'},
  {c:'语法',q:'表达"这附近有...吗？"最常用的句型是？',o:['Is there a _____ nearby / near here?','Are there any _____ here?','Can I find _____ here?','A和B都正确，B适合询问多个地点'],a:3,e:'"Is there a pharmacy nearby?"（附近有药店吗？）询问单数；"Are there any restaurants near here?"（附近有餐厅吗？）询问多个。两种都是日常询问的高频句型。'},
  {c:'语法',q:'"Can I / May I / Could I"三者都可以表达请求，哪个最礼貌？',o:['May I最正式礼貌，Could I次之，Can I最口语化','三者礼貌程度完全相同','Can I最礼貌','Could I只用于书面'],a:0,e:'礼貌程度：May I（最正式/礼貌）> Could I（礼貌）> Can I（口语）。在正式场合（海关、餐厅点餐）用"May I"或"Could I"，朋友间用"Can I"。'},
  {c:'语法',q:'"I\'m not sure, but I think..."和"I\'m certain that..."有什么区别？',o:['前者表示不确定，后者表示确定；诚实地表达确定程度在旅行中很重要','两者表达相同的确定性','前者更礼貌','后者只用于书面'],a:0,e:'诚实表达确定程度很重要：不确定时说"I think..."或"I believe..."；确定时说"I\'m sure..."。在问路时说"I\'m not sure, you might want to check Google Maps."比乱说方向要好。'},
  {c:'语法',q:'询问"这道菜是怎么做的？"英语怎么说？',o:['How is this dish prepared / made?','What is this dish?','Is this dish cooked?','How much does this cost?'],a:0,e:'"How is it prepared?"=怎么制作的？可以了解烹饪方法（grilled烤/fried炸/steamed蒸/raw生食等），对有饮食限制的人非常重要。'},
  {c:'语法',q:'表达"我已经等了很长时间了"，以下哪个句子语法正确？',o:['I\'ve been waiting for a long time.','I waited for a long time.','I\'m waiting since one hour.','I have waited since long.'],a:0,e:'表示"从过去持续到现在"用现在完成进行时（Present Perfect Continuous）：have/has been + V-ing。"I\'ve been waiting for 30 minutes."=我已经等了30分钟了。是向服务员表达等太久时的有效句型。'},
  {c:'语法',q:'"Would you recommend...?"和"What do you recommend?"有什么区别？',o:['"Would you recommend X?"是推荐X这个具体选项吗；"What do you recommend?"是开放式问你推荐什么','两者完全相同','前者只用于餐厅','后者只用于博物馆'],a:0,e:'"Would you recommend the seafood pasta?"=你推荐这道海鲜意面吗？"What do you recommend?"=你推荐什么？（让对方提建议）都是高频实用问句，后者更开放灵活。'},
  {c:'语法',q:'你需要在电话里拼写你的名字，字母"B"和"D"容易混淆，英语中有什么方法？',o:['用单词辅助拼写：B as in Boy, D as in Dog（这叫Phonetic Alphabet/spelling alphabet）','用更大声的声音重复','用中文解释','只用手机发短信避免通话'],a:0,e:'英语中的NATO Phonetic Alphabet（拼写字母表）：A=Alpha, B=Bravo, C=Charlie, D=Delta, E=Echo...用单词辅助拼写避免混淆，在嘈杂环境下尤其有效。'},
  {c:'语法',q:'"It\'s not working."和"It\'s broken."有什么细微区别？',o:['It\'s not working=当前不能用（可能是暂时的），It\'s broken=已损坏（通常是永久性）；实际旅行中两者常互换使用','两者意思完全不同，不能互换','broken更礼貌','not working只用于机器'],a:0,e:'向酒店报告问题时两者都可以用："The air conditioning isn\'t working."或"The TV is broken."酒店工作人员会明白需要维修或更换，语义差别不大。'},
  {c:'语法',q:'如何礼貌地中断别人来问路？最常用的开场白是？',o:['Excuse me, sorry to bother you, could you help me?','Hey you!','Oi!','Stop!'],a:0,e:'"Excuse me"是打断陌生人最礼貌的方式，后接"sorry to bother you"更好。然后说明你的需求："I\'m looking for the museum. Could you point me in the right direction?"'},
  {c:'语法',q:'"The more, the merrier."这句英语谚语在旅行邀请中是什么意思？',o:['人越多越热闹（欢迎更多人加入）','景区人多不好','旅行团越大越便宜','这句话没有实际意义'],a:0,e:'"The more, the merrier."=人越多越好/越热闹，是"越...越..."（The + 比较级，the + 比较级）的固定句式。邀请朋友一起旅行时常用这句话表达欢迎。'},
  {c:'语法',q:'"Mind the gap!"是什么意思？在哪里常听到？',o:['注意列车与站台之间的空隙！（英国伦敦地铁标志性广播）','当心台阶','小心道路','注意前方关闭的门'],a:0,e:'"Mind the gap!"是伦敦地铁（Tube）最著名的广播提示，提醒乘客注意列车与站台边缘之间的空隙，防止跌落。也已成为伦敦的文化符号，印在各种纪念品上。'},
  {c:'语法',q:'表达"今天稍后我想去..."和"明天我们将要..."，正确的时态是？',o:['今天稍后：I\'m going to / I\'ll / I\'m planning to...；明天：We will / We\'re going to...','两者都用过去时','两者都用现在完成时','只能用will，不能用going to'],a:0,e:'"Going to"（计划好的）和"Will"（临时决定/更确定的未来）都可以表达未来。I\'m going to visit the museum this afternoon.（已计划好）/ I\'ll have a coffee.（临时决定）'},
  {c:'语法',q:'你想确认某地的营业时间，哪个问句最简洁自然？',o:['What are your opening hours? / Are you open on Sundays?','When do you open and close?','Do you operate on weekends?','所有选项都正确且自然'],a:3,e:'询问营业时间的多种表达都正确自然："What are your hours?"（最简洁）/ "Are you open now?"（询问当前状态）/ "What time do you close?"（关注打烊时间）。旅行前打电话确认很有必要！'}
);

